import sqlite3

def search(filters):
    conn = sqlite3.connect('example.db')
    cur = conn.cursor()
    
    conditions = []
    params = {}
    
    for filter in filters:
        field = filter['field']
        op = filter['op']
        value = filter['value']
        
        if op == '=':
            condition = f"{field} = ?"
        elif op == '>':
            condition = f"{field} > ?"
        elif op == '<':
            condition = f"{field} < ?"
        elif op == 'LIKE':
            condition = f"{field} LIKE ?"
        
        conditions.append(condition)
        params[f"{field}_{op}"] = value
    
    query = "SELECT * FROM table WHERE " + " AND ".join(conditions)
    
    cur.execute(query, params)
    results = cur.fetchall()
    
    conn.close()
    return results

